    fn windows_bin_paths_for_install_path(install_path: &Path) -> Vec<std::path::PathBuf> {
        let bin_dir = install_path.join("bin");
        if bin_dir.exists() {
            vec![bin_dir]
        } else {
            vec![install_path.to_path_buf()]
        }
    }
